int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int L, Q;
    scanf("%d", &L);
    int A[L];
    for (int i = 0; i < L; i++) {
        scanf("%d", &A[i]);
    }
    scanf("%d", &Q);
    while (Q--) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int i, v;
            scanf("%d %d", &i, &v);
